section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "testing-pytest-output",
  "required": [
    "test_files",
    "fixture_count",
    "parametrize_uses",
    "scope_distribution",
    "coverage_threshold",
    "forbidden_seen"
  ],
  "properties": {
    "test_files": {
      "description": "Paths of `test_*.py` produced."
    },
    "fixture_count": {
      "description": "Total fixtures across `conftest.py` files."
    },
    "parametrize_uses": {
      "description": "Number of `@pytest.mark.parametrize` decorators."
    },
    "scope_distribution": {
      "description": "Counts of `function`/`class`/`module`/`session` fixtures."
    },
    "coverage_threshold": {
      "description": "Minimum % required in CI."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
